INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Case & Matter Management$q$, $q$Centralizes documents, notes, contacts, tasks, and calendar events for each matter so the full case history lives in one place.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Time Tracking & Billing$q$, $q$Lets attorneys and staff log billable hours or flat fees against a matter and turn that activity directly into client invoices.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Online Payments$q$, $q$Integrates with LawPay so clients can pay invoices online by card or eCheck, with support for trust-accounting-compliant transactions.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Client Portal$q$, $q$Gives clients secure, self-service access to case updates, shared documents, invoices, and secure messaging outside of email.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Document Management$q$, $q$Provides cloud-based storage, version tracking, and reusable templates so files stay organized within their related matter.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Court Rules Calendaring$q$, $q$Automatically calculates and populates key deadlines and hearing dates based on jurisdiction and case type.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Task & Workflow Management$q$, $q$Assigns and tracks tasks tied to specific matters so staff can see what is due and who is responsible for it.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Lead & Client Intake$q$, $q$Tracks prospective clients from first contact through retention, helping firms manage their pipeline alongside active matters.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Reporting & Analytics$q$, $q$Surfaces billing realization, outstanding balances, and staff productivity data to help firms monitor financial health.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Combines case management, billing, and client communication in a single subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Native LawPay integration simplifies accepting online client payments$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Client portal reduces routine status-update calls and emails$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Mobile apps support time tracking and document review away from the office$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Tiered plans let firms start small and add features as they grow$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Per-user, per-month pricing can add up for larger teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Some advanced features, such as certain reporting or payment tools, are gated behind higher-tier plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Migrating existing contacts, documents, and billing history takes real setup effort$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Offers less deep customization than platforms built for large enterprise firms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Court-rule calendaring and billing structures are built primarily around U.S. legal practice$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$What is MyCase used for?$q$, $q$MyCase is legal practice management software used by law firms to manage cases, track billable time, generate invoices, store documents, calendar deadlines, and communicate with clients through a secure portal.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Does MyCase offer a free trial?$q$, $q$Yes, MyCase offers a free trial period so firms can evaluate the platform's case management, billing, and client communication features before committing to a paid plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$How much does MyCase cost?$q$, $q$MyCase is priced per user per month, with plans starting around $39 per user when billed annually and higher tiers unlocking additional billing, reporting, and client intake features.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Does MyCase integrate with other software?$q$, $q$MyCase integrates with tools such as LawPay for online payments and offers additional integrations for accounting and document workflows, depending on the plan.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Is MyCase available on mobile devices?$q$, $q$Yes, MyCase provides native iOS and Android apps so attorneys and staff can track time, review documents, and message clients while away from the office.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Solo attorney consolidating billing and case files$q$, $q$A solo practitioner replaces spreadsheets and separate invoicing tools with MyCase to track time, generate invoices, and store documents for every matter in one place.$q$, $q$Solo attorneys$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Family law firm managing client communication$q$, $q$A small family law firm uses the client portal to share documents and case updates directly with clients, reducing routine phone calls and status-check emails.$q$, $q$Small family law firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Personal injury firm tracking deadlines and documents$q$, $q$A personal injury practice relies on court-rules calendaring and centralized document storage to keep multiple active cases and their deadlines organized.$q$, $q$Personal injury firms$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Firm migrating from paper and generic tools$q$, $q$A growing practice moves from paper files, email, and a shared drive to a single system covering case management, billing, and online client payments.$q$, $q$Small to midsize law firms$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Basic$q$, $q$$39 per user/month$q$, $q$Billed annually$q$, $q$["Case and document management","Calendaring","Client portal","Basic invoicing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Pro$q$, $q$$79 per user/month$q$, $q$Billed annually$q$, $q$["Everything in Basic","Advanced billing and time tracking","Task management","Reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$Advanced$q$, $q$$99 per user/month$q$, $q$Billed annually$q$, $q$["Everything in Pro","Lead and client intake tools","Advanced reporting","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MyCase is a cloud-based legal practice management platform built for solo attorneys and small to midsize law firms. Launched in 2010, it was designed to replace the patchwork of spreadsheets, email threads, and paper files that many smaller practices rely on with a single system for managing cases, clients, billing, and communication. The platform is now part of AffiniPay's family of legal technology products, sitting alongside tools like LawPay for online payments.$q$, $q$At its core, MyCase organizes a firm's work around the matter: every case file brings together documents, notes, tasks, calendar events, time entries, invoices, and client messages in one place. This case-centric structure is meant to reduce the time attorneys and staff spend hunting across email, shared drives, and separate billing software, and to give everyone on a matter, including the client, a consistent view of where things stand.$q$, $q$Because MyCase integrates directly with LawPay for online payments and offers native e-signature, document management, and a client portal, firms can often run day-to-day operations without stitching together several point solutions. It is positioned less as a niche tool for a single task and more as an all-in-one operating system for the business side of running a law practice.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$who-mycase-is-for$q$, $q$Who MyCase Is For$q$, 2, ARRAY[$q$MyCase is aimed squarely at solo practitioners and small firms, generally those with a handful of attorneys up through a few dozen, who need practice management, billing, and client communication in one product rather than several disconnected tools. Firms that bill by the hour or flat fee and want time tracking tied directly to case files and invoices are a natural fit.$q$, $q$It tends to work well for general practice firms and for practice areas with steady client-facing communication needs, such as family law, personal injury, immigration, and estate planning, where a client portal and automated updates can cut down on routine status-check calls. Firms that value a straightforward, guided workflow over deep configurability often find the platform comfortable to adopt.$q$, $q$MyCase is also a good match for firms migrating away from generic tools, spreadsheets for billing, a shared drive for documents, and a paper calendar for deadlines, into a single dedicated system. Because it bundles case management, billing, and payments, firms that want to consolidate vendors and reduce the number of subscriptions they juggle are typically strong candidates.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large firms with complex organizational structures, multiple offices, or specialized departmental workflows may find MyCase more limited than platforms built specifically for bigger enterprises. Firms that need granular permission structures, elaborate conflict-checking across hundreds of timekeepers, or deep customization of billing rules may outgrow what the core product offers.$q$, $q$Firms with heavy dependence on a specific niche practice-area tool, such as specialized bankruptcy, patent prosecution, or litigation-support software with deep docketing automation, may find that MyCase does not replace those systems and instead has to run alongside them. Firms wanting a single system that natively covers highly specialized workflows out of the box should evaluate this gap carefully.$q$, $q$Firms outside the United States may also find MyCase a weaker fit, since its billing structures, court-rule calendaring, and payment integrations are built primarily around U.S. legal practice. Finally, firms hoping for a perpetually free tool or one with no per-user subscription cost should look elsewhere, since MyCase is a paid, per-seat product.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$MyCase's foundation is case and matter management: every matter has a dedicated file for documents, contacts, notes, and a shared calendar. Document management includes cloud storage, version tracking, and templates, while calendaring supports court-rules-based deadline calculation so key dates are automatically populated based on jurisdiction and case type.$q$, $q$Billing and time tracking are tightly integrated with case activity, letting timekeepers log hours or flat fees directly against a matter and generate invoices from that data. Through the LawPay integration, firms can accept credit card and eCheck payments online, including trust-accounting-compliant transactions, and clients can pay invoices directly through the portal.$q$, $q$The client portal gives clients secure access to case updates, documents, invoices, and messaging without relying on email. MyCase also includes lead and intake tools to help firms track prospective clients from first contact through retention, along with built-in reporting on billing realization, outstanding balances, and staff productivity.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4459135-cfd3-4027-bdc1-046357985283', $q$the-mycase-experience$q$, $q$The MyCase Experience$q$, 2, ARRAY[$q$Day to day, MyCase presents a fairly clean, dashboard-driven interface organized around tasks, calendar events, and recent case activity, and most firms can get a basic setup running within the first few weeks. Onboarding typically involves importing existing contacts and documents and configuring billing rates, which takes real effort but is manageable for a small team.$q$, $q$Mobile apps for iOS and Android let attorneys log time, review documents, and message clients from outside the office, which matters for practitioners who spend significant time in court or meetings. In practice, the experience feels most complete for firms that commit to using MyCase as their single system of record rather than as one tool among many.$q$, $q$Support resources include live chat, phone support, and self-service help content, and most users describe the learning curve as moderate rather than steep. Overall, the day-to-day experience is that of a purpose-built, if occasionally rigid, system: it rewards firms that adapt their workflow to its structure more than it accommodates firms wanting to heavily customize the platform to fit an existing process.$q$]::text[], 4);
