INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('76f0c5ad-2a6b-4da7-9d21-98785efc0c74', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Visual node-based editor$q$, $q$Build workflows by connecting nodes on a flowchart-style canvas, with live data previews at each step for easy debugging.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Hundreds of app integrations$q$, $q$Pre-built nodes cover popular SaaS tools, databases, and messaging platforms, alongside generic HTTP and webhook nodes for anything else.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Custom code nodes$q$, $q$Drop into raw JavaScript or Python inside any workflow step when a pre-built node doesn't cover the exact logic needed.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$AI and LangChain-style nodes$q$, $q$Connect to large language models, vector stores, and memory components to build AI agents and retrieval-augmented workflows.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Fair-code self-hosting$q$, $q$Run n8n on your own infrastructure for free under a sustainable-use license, keeping full control over data and execution costs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Flexible triggers$q$, $q$Start workflows from webhooks, scheduled jobs, form submissions, or events emitted by connected apps.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Error handling and version history$q$, $q$Configure retries and error workflows, and roll back to previous workflow versions when something breaks.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Built-in credential management$q$, $q$Store and reuse API keys and OAuth connections securely across multiple workflows without re-entering them.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Community template library$q$, $q$Start from thousands of shared workflow templates instead of building common automations from scratch.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Scalable execution modes$q$, $q$Queue mode and worker scaling options let heavier workloads run reliably in self-hosted or enterprise deployments.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Free to self-host with full source access under a fair-code license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Combines visual building blocks with real code for maximum flexibility$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Transparent data view at every workflow step simplifies debugging$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Strong and growing set of AI agent and LLM-related nodes$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Large community template library speeds up building common automations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Steeper learning curve than fully guided, beginner-focused automation tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Self-hosting requires managing updates, backups, and server security yourself$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Cloud plans still require thinking about execution volume and workflow design$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Some integrations rely on generic HTTP nodes rather than official connectors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Complex workflows with many code nodes can become harder to maintain over time$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Is n8n free to use?$q$, $q$Yes, n8n can be self-hosted for free under its fair-code sustainable-use license. n8n also offers paid n8n Cloud plans for teams that prefer a fully hosted service.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Do I need to know how to code to use n8n?$q$, $q$No, but coding knowledge helps. Many workflows can be built with drag-and-drop nodes alone, while custom JavaScript or Python nodes are available for advanced logic.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$How is n8n different from Zapier or Make?$q$, $q$n8n offers a free self-hosting option, deeper customization through code nodes, and transparent access to the underlying source, whereas Zapier and Make are fully closed SaaS products.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Can n8n be used to build AI agents?$q$, $q$Yes, n8n includes AI-oriented nodes for connecting to large language models, vector stores, and memory, allowing users to build agent-style and retrieval-augmented workflows.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$What does self-hosting n8n involve?$q$, $q$Self-hosting typically means running n8n via Docker or a similar setup on your own server, and taking responsibility for updates, backups, and security, in exchange for no per-execution fees.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Marketing operations automation$q$, $q$Sync leads, contacts, and campaign data between CRMs, email tools, and analytics platforms without manual data entry.$q$, $q$Marketing and RevOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Internal IT and DevOps automation$q$, $q$Automate alerting, ticket creation, and routine maintenance tasks by connecting monitoring tools, chat apps, and internal systems.$q$, $q$IT and DevOps teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Cross-app data synchronization$q$, $q$Keep data consistent across databases, spreadsheets, and SaaS tools with scheduled or event-driven sync workflows.$q$, $q$Operations and data teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$AI agent orchestration$q$, $q$Chain LLM calls, tool actions, and external data lookups together to power chatbots and autonomous task agents.$q$, $q$AI and product engineering teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Community (self-hosted)$q$, $q$Free$q$, $q$N/A$q$, $q$["Unlimited workflows","Full node library and code nodes","Self-host on your own infrastructure","Fair-code license","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Cloud Starter$q$, $q$From around $20/month$q$, $q$Monthly or annual$q$, $q$["Fully hosted n8n instance","Limited workflow executions","Automatic updates","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Cloud Pro$q$, $q$From around $50/month$q$, $q$Monthly or annual$q$, $q$["Higher execution limits","More concurrent workflow runs","Shared team environments","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual contract$q$, $q$["SSO and advanced permissions","Dedicated support and SLA","Scalable queue-mode deployment options","Onboarding and account management"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$n8n is a workflow automation and integration platform that lets teams connect apps, APIs, and internal systems using a visual, node-based canvas. Unlike many closed automation tools, n8n is source-available under a fair-code, sustainable-use license, so anyone can self-host it for free, inspect the code, and extend it, while n8n GmbH sells hosted cloud plans and enterprise features to fund development.$q$, $q$Founded in 2019 in Berlin, Germany, n8n grew out of frustration with the rigid, black-box nature of typical no-code automation tools. Its combination of drag-and-drop nodes with the option to drop into raw JavaScript or Python inside any step makes it popular with developers who want the speed of no-code without giving up programmability when logic gets complex.$q$, $q$Today n8n supports hundreds of app integrations plus generic HTTP, database, and webhook nodes, and has added a dedicated set of AI nodes for building LLM-powered agents, chatbots, and retrieval-augmented workflows. It sits at the intersection of iPaaS tools like Zapier and Make and code-first automation frameworks, aiming to serve both technical and semi-technical users on one platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$who-n8n-is-for$q$, $q$Who n8n Is For$q$, 2, ARRAY[$q$n8n is built for developers, technical marketers, IT and ops teams, and startups that need to automate multi-step processes across many tools but don't want to be boxed in by a rigid low-code builder. If a workflow requires custom logic, unusual data transformations, or calling an internal API that no pre-built connector covers, n8n's code nodes make that straightforward.$q$, $q$It also suits privacy- and cost-conscious organizations. Because it can be self-hosted on a company's own servers or a modest VPS, teams handling sensitive data or running high execution volumes can avoid per-task pricing entirely and keep workflows inside their own infrastructure, something pure SaaS automation tools generally don't allow.$q$, $q$Agencies and consultancies that build automations for multiple clients also gravitate to n8n because of its flexibility and the fair-code license's generous self-hosting terms, and increasingly AI teams use it to orchestrate multi-step LLM agent workflows that combine tool calls, memory, and external data sources.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$n8n is not the best fit for complete non-technical users who want the simplest possible experience. While the canvas is visual, building anything beyond a basic trigger-action workflow often benefits from at least some comfort with JSON, expressions, or light scripting, and the learning curve is steeper than fully guided tools aimed at absolute beginners.$q$, $q$Teams that want a fully managed, zero-maintenance SaaS product with no infrastructure thinking at all may prefer a simpler tool, since self-hosting n8n means owning updates, backups, and server security, and even the cloud plans still ask users to think about execution volume and workflow design.$q$, $q$Organizations with strict requirements for a single vendor's fully closed, audited enterprise stack, or who need every integration to be an officially certified connector rather than a community-built or generic HTTP-based one, may find some gaps compared to the largest incumbent automation platforms.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$n8n's core strength is its node-based visual editor, where each step in a workflow is represented as a node that can be an app integration, a code block, a condition, or an AI action, all connected on a flowchart-like canvas that makes complex logic easy to trace.$q$, $q$Beyond visual building blocks, n8n supports writing custom JavaScript or Python directly inside a node, calling any REST or GraphQL API generically, and manipulating data with built-in expression syntax, so workflows are never limited to what a pre-built connector exposes. Triggers include webhooks, scheduled jobs, and app-specific events.$q$, $q$More recently, n8n added AI-specific nodes for connecting to large language models, vector stores, and memory, enabling agent-style workflows where an LLM can decide which tool or step to call next. Combined with error handling, retry logic, and version history, this makes n8n suited to both simple syncs and sophisticated automations.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2345d0ed-4255-4773-9565-b0ced4967bcd', $q$the-n8n-experience$q$, $q$The n8n Experience$q$, 2, ARRAY[$q$Using n8n day to day feels closer to using a whiteboard than filling out a form. New users start from a blank canvas or one of the many community-shared templates, drag nodes onto it, and wire them together, testing each step's output as they go, which makes debugging a broken step much faster than in tools that only show a workflow's final result.$q$, $q$The interface exposes real data at every step, so users can see exactly what JSON is flowing between nodes, which lowers the mystery around why an automation did or didn't fire correctly. This transparency is a deliberate design choice and is often cited as one of n8n's biggest advantages over more opaque competitors.$q$, $q$For teams that self-host, the initial setup via Docker or a cloud server takes some technical effort, but ongoing maintenance is manageable, and the interface itself feels the same whether running locally or through n8n Cloud. Overall the experience rewards a bit of upfront learning with long-term flexibility and control.$q$]::text[], 4);
