INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cf2565ff-7160-42e9-8d6c-efdb9830004d', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Git-based continuous deployment$q$, $q$Automatically builds and deploys sites from GitHub, GitLab, or Bitbucket on every push, with no manual server configuration required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Deploy previews$q$, $q$Generates a unique preview URL for every pull request so teams and stakeholders can review changes before merging to production.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Instant rollbacks$q$, $q$Lets teams revert to any previous deploy immediately if a release introduces a bug or regression.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Serverless and edge functions$q$, $q$Runs backend logic on-demand near users without managing dedicated servers, supporting both scheduled and on-request execution.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Global CDN$q$, $q$Distributes static assets and pages across a worldwide edge network for fast load times regardless of visitor location.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Form handling$q$, $q$Captures and processes HTML form submissions automatically without requiring a separate backend service.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Netlify Identity$q$, $q$Provides built-in user authentication and access control that integrates directly with deployed sites.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Split testing$q$, $q$Enables A/B testing across different deploy branches to measure the impact of changes on real traffic.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Large media and asset optimization$q$, $q$Manages and optimizes images and large files through Git-friendly workflows to keep repositories lean.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Redirects and custom headers$q$, $q$Allows routing rules, custom headers, and access control to be defined as code alongside the project.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Extremely fast setup from a Git repository to a live, globally distributed site$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Deploy previews make reviewing changes easy for both developers and non-technical stakeholders$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Generous free tier suitable for personal projects, prototypes, and small sites$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Strong support for modern frameworks and static site generators out of the box$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Instant rollbacks and clear deploy history reduce the risk of shipping mistakes$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Costs can rise quickly for high-traffic sites or function-heavy applications$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Serverless function limits may constrain complex or long-running backend workloads$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Less suited to teams needing full control over infrastructure or on-premises hosting$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Build minute and bandwidth quotas require active monitoring on busier projects$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Some advanced features are gated behind higher-priced or enterprise plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$What is Netlify used for?$q$, $q$Netlify is used to build, deploy, and host modern websites and web applications, automating the process from a Git commit to a live, globally distributed site.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Does Netlify offer a free plan?$q$, $q$Yes, Netlify has a free Starter tier suitable for personal projects and small sites, with paid plans available as teams and traffic grow.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Can Netlify host dynamic or server-rendered applications?$q$, $q$Yes, Netlify supports frameworks like Next.js, Astro, and Remix through serverless and edge functions, in addition to static site hosting.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$How does Netlify pricing work?$q$, $q$Netlify combines a free tier with per-member paid plans and usage-based charges for bandwidth, build minutes, and function invocations beyond included limits.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Does Netlify require DevOps expertise to use?$q$, $q$No, Netlify is designed to minimize infrastructure management, letting developers deploy sites through Git without configuring servers directly.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Marketing and landing page sites$q$, $q$Teams deploy fast-loading marketing pages with instant preview links for stakeholder review before launch.$q$, $q$Marketing teams and small businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Documentation and content sites$q$, $q$Static site generators paired with Netlify deliver fast, version-controlled documentation and blogs.$q$, $q$Developer relations and content teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Full-stack web applications$q$, $q$Frameworks like Next.js run on Netlify with serverless and edge functions handling backend logic and APIs.$q$, $q$Product and engineering teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Client and agency project delivery$q$, $q$Agencies use deploy previews and rollbacks to manage multiple client sites with fast iteration cycles.$q$, $q$Digital agencies and freelance developers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Starter$q$, $q$Free$q$, $q$N/A$q$, $q$["Continuous deployment from Git","Deploy previews","Global CDN hosting","Limited build minutes and function invocations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Pro$q$, $q$$19/month per member$q$, $q$Monthly or annual$q$, $q$["Increased build minutes and bandwidth","Background functions","Password-protected sites","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$Enterprise$q$, $q$Custom$q$, $q$Annual contract$q$, $q$["Advanced security and compliance controls","Dedicated support and SLAs","Custom usage limits","Single sign-on"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Netlify is a cloud platform built for teams that want to ship websites and web applications without managing their own servers. It grew out of the JAMstack movement, pairing static site generation and modern frontend frameworks with a global content delivery network, so builds triggered by a Git push are automatically deployed to production in seconds.$q$, $q$At its core, Netlify combines continuous deployment, serverless and edge functions, form handling, identity and authentication, and analytics into a single workflow. Developers connect a repository from GitHub, GitLab, or Bitbucket, and Netlify handles the build pipeline, preview deployments for every pull request, and rollback to any prior deploy with a click.$q$, $q$Over time the platform has expanded well beyond static hosting to support server-rendered frameworks like Next.js, Astro, Remix, and SvelteKit, positioning itself as a general-purpose deployment layer for the modern web rather than a niche static-hosting tool.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$who-netlify-is-for$q$, $q$Who Netlify Is For$q$, 2, ARRAY[$q$Netlify is well suited to frontend developers, small engineering teams, and agencies who want to go from a Git repository to a live, globally distributed site with minimal DevOps overhead. It fits naturally into workflows already built around modern JavaScript frameworks and static site generators.$q$, $q$Marketing teams and content-driven organizations also benefit, since preview deployments make it easy for non-engineers to review changes before they go live, and integrations with headless CMS platforms streamline publishing without touching infrastructure.$q$, $q$Startups and product teams that need to iterate quickly on landing pages, documentation sites, or full applications appreciate the fast feedback loop, generous free tier for experimentation, and the ability to scale up to paid plans only once traffic or team size actually demands it.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams running large, stateful backend systems with heavy database workloads, long-running processes, or complex custom networking requirements may find Netlify's serverless-first model restrictive, since it is designed around ephemeral functions and edge compute rather than persistent servers.$q$, $q$Organizations with strict data residency or on-premises hosting requirements, or those needing deep low-level control over infrastructure, may prefer traditional cloud providers or self-hosted setups instead of a managed platform like Netlify.$q$, $q$Very high-traffic applications with unpredictable, function-heavy workloads should also budget carefully, since usage-based costs for bandwidth, build minutes, and serverless invocations can grow quickly compared to a self-managed server at fixed cost.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Netlify's core offering centers on Git-based continuous deployment: every commit triggers an automatic build and deploy, every pull request gets its own shareable preview URL, and instant rollbacks make shipping mistakes low-risk. This is layered on top of a global edge network for fast content delivery.$q$, $q$Beyond static hosting, Netlify provides serverless functions and edge functions for running backend logic close to users, built-in form handling without a separate backend, and Netlify Identity for authentication. Split testing and analytics add further layers for teams optimizing conversion and performance.$q$, $q$The platform also supports large media handling, redirects and header rules configured directly in code, and a marketplace of integrations with CMS platforms, e-commerce tools, and monitoring services, letting teams extend functionality without leaving the deployment workflow.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26474910-f9a4-4767-aebb-d9caf5983498', $q$the-netlify-experience$q$, $q$The Netlify Experience$q$, 2, ARRAY[$q$Day-to-day, using Netlify feels lightweight: connecting a repository takes minutes, build configuration lives in a simple file alongside the codebase, and the dashboard clearly surfaces deploy status, logs, and preview links without requiring deep infrastructure knowledge.$q$, $q$The developer experience is generally praised for its speed and clarity, particularly the deploy preview workflow, which turns code review into something stakeholders can actually click through and see live before merging, reducing back-and-forth during launches.$q$, $q$Where the experience gets more demanding is around cost visibility and function limits at scale, where teams running complex applications need to actively monitor usage, build minutes, and bandwidth to avoid surprises, and may need to combine Netlify with other services for heavier backend needs.$q$]::text[], 4);
