INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Practice Management System Sync$q$, $q$Real-time, two-way synchronization with supported dental and medical practice management systems keeps schedules and patient data consistent.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Online Scheduling Widget$q$, $q$An embeddable booking widget lets patients view live availability and schedule appointments directly from the practice's website.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Automated Reminders and Recall$q$, $q$Automated text and email reminders help reduce missed appointments and re-engage patients who are due for follow-up visits.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Two-Way Patient Texting$q$, $q$Staff can send and receive text messages with patients directly, streamlining communication without relying solely on phone calls.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Digital Forms and Intake$q$, $q$Patients can complete intake, consent, and update forms online before their visit, reducing paperwork at the front desk.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Online Bill Pay$q$, $q$Patients can view and pay balances online, giving practices another channel to collect payments beyond in-office transactions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Multi-Location Dashboard$q$, $q$A centralized dashboard gives dental groups and health systems visibility into bookings and activity across multiple office locations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Developer API$q$, $q$An API allows developers to build custom applications that read and write scheduling and patient data from supported systems.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Website Booking Integration$q$, $q$Scheduling tools are designed to integrate into a practice's existing website rather than requiring patients to leave for a separate portal.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Deep, real-time synchronization with widely used dental and medical practice management systems$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Reduces front-desk phone volume through self-service online booking$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Combines scheduling, reminders, texting, forms, and payments in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$API access appeals to developers and organizations building custom integrations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Well suited to multi-location dental groups needing centralized oversight$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Pricing is not publicly listed, requiring a sales conversation to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Value depends heavily on using a supported practice management system$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$May be more platform than very small single-location practices need$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Initial integration setup can require IT or vendor coordination$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Primarily focused on dental and healthcare, limiting use outside that vertical$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$What is NexHealth used for?$q$, $q$NexHealth is used by dental and healthcare practices to offer online appointment scheduling, automated reminders, patient texting, digital forms, and online bill pay, all synchronized with their existing practice management system.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$How much does NexHealth cost?$q$, $q$NexHealth does not publish standard pricing. Practices need to contact NexHealth directly for a quote based on their size, location count, and the features they need.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Does NexHealth integrate with practice management systems?$q$, $q$Yes, NexHealth's core capability is real-time synchronization with a range of dental and medical practice management systems, keeping schedules and patient data consistent across both.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Is NexHealth only for dental practices?$q$, $q$NexHealth started with a strong focus on dental practices but also serves broader healthcare clinics, particularly those using compatible practice management or electronic health record systems.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Does NexHealth offer an API for developers?$q$, $q$Yes, NexHealth provides an API that lets developers and health-tech companies build custom scheduling and patient engagement tools on top of supported practice management systems.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Reducing No-Shows with Automated Reminders$q$, $q$A dental office uses NexHealth's automated text and email reminders to cut down on missed appointments and last-minute cancellations.$q$, $q$Dental practice managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Standardizing Booking Across Multiple Locations$q$, $q$A dental service organization uses NexHealth's centralized dashboard to give every location the same online scheduling experience while keeping each office's calendar accurate.$q$, $q$Multi-location dental groups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Cutting Front-Desk Call Volume$q$, $q$A busy clinic embeds NexHealth's scheduling widget on its website so patients can book directly online instead of calling during business hours.$q$, $q$Healthcare clinic administrators$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Building Custom Patient Tools$q$, $q$A health-tech developer uses NexHealth's API to build a custom patient app that reads and writes appointment data from a client's practice management system.$q$, $q$Health-tech developers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Custom Plan$q$, $q$Contact for pricing$q$, $q$Custom$q$, $q$["Practice management system synchronization","Online scheduling widget","Automated reminders and recall messaging","Two-way patient texting","Digital forms and online bill pay"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Enterprise / Multi-Location$q$, $q$Contact for pricing$q$, $q$Custom$q$, $q$["Centralized multi-location dashboard","API access for custom integrations","Dedicated onboarding and support","Scalable rollout across dental service organizations"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$NexHealth is a patient engagement and scheduling platform built primarily for dental and healthcare practices that need to modernize how patients book appointments, communicate with the office, and pay their bills. At its core is a synchronization engine that connects directly to legacy practice management systems, allowing real-time appointment data to flow between the front desk software and web-based patient tools without manual double entry.$q$, $q$The platform is best known for powering online scheduling widgets that practices embed on their own websites, letting patients see live availability and book visits instantly rather than calling in. Around that core scheduling capability, NexHealth layers appointment reminders, two-way texting, digital forms, and online payment collection, positioning itself as an operational hub rather than a single-purpose booking tool.$q$, $q$NexHealth differentiates itself through its developer-facing API and its compatibility with a wide range of practice management systems commonly used in dental and medical offices. This integration-first approach makes it a common choice for multi-location dental groups, dental service organizations, and health systems that need scheduling and communication tools to work with the software they already run day to day.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$who-nexhealth-is-for$q$, $q$Who NexHealth Is For$q$, 2, ARRAY[$q$NexHealth is designed for dental practices, dental service organizations, and healthcare clinics that rely on an existing practice management system and want to add modern, patient-facing digital tools on top of it rather than replacing that system entirely. Practices already using platforms like Dentrix, Eaglesoft, or Open Dental are a natural fit because NexHealth's synchronization layer is built to work with these systems.$q$, $q$Multi-location dental groups and dental support organizations are a particularly strong match, since NexHealth's centralized dashboard and API can standardize online booking, reminders, and forms across many offices while still reflecting each location's real-time schedule. Practice administrators and operations teams who want to reduce phone call volume and no-show rates also benefit from the automated reminder and communication tools.$q$, $q$Software developers and health-tech companies building patient-facing products are another core audience, since NexHealth exposes an API that lets outside applications read and write scheduling, patient, and billing data from supported practice management systems. This makes it relevant not only to practices themselves but to vendors building adjacent tools in the dental and healthcare technology ecosystem.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo practitioners or very small single-location offices with a tight technology budget may find NexHealth's feature set and setup process more elaborate than what they need, especially if their existing phone-based scheduling workflow is already manageable. Simpler, lower-cost booking widgets may serve very small practices adequately without the integration overhead.$q$, $q$Practices running a practice management system that NexHealth does not support, or that operate largely on paper-based scheduling, will not be able to take advantage of the platform's core synchronization strength and should look for tools built around their specific software stack instead.$q$, $q$Organizations outside the dental and healthcare vertical, or those wanting a general-purpose scheduling tool for unrelated industries, are also not the intended audience. NexHealth's product decisions, terminology, and integrations are shaped specifically around dental and medical office workflows, which makes it less suitable as a generic appointment booking solution.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$NexHealth's central feature is its real-time synchronization with practice management systems, which keeps appointment slots, patient records, and provider schedules consistent between the office's existing software and NexHealth's patient-facing tools. This eliminates the manual reconciliation that often comes with bolt-on scheduling widgets.$q$, $q$On top of synchronization, NexHealth offers online scheduling embeds for practice websites, automated appointment reminders and recall messaging, two-way patient texting, digital intake and consent forms, and online bill pay. These features are aimed at reducing front-desk workload while giving patients more convenient, self-service ways to interact with the practice.$q$, $q$For technical teams, NexHealth provides an API that developers can use to build custom scheduling and patient communication experiences on top of supported practice management systems, along with a dashboard for practice administrators to monitor bookings, messages, and payment activity across one or multiple locations.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$the-nexhealth-experience$q$, $q$The NexHealth Experience$q$, 2, ARRAY[$q$Setting up NexHealth typically involves connecting the platform to the practice's existing management system so that appointment and patient data can sync in real time, followed by configuring the online scheduling widget and communication preferences to match the practice's workflow and branding.$q$, $q$Once configured, the day-to-day experience centers on a dashboard where staff can see incoming online bookings, manage automated reminders, respond to patient texts, and track digital form completion and payments, all reflecting the same underlying schedule used at the front desk.$q$, $q$For developers, the experience is centered on the API documentation and sandbox tools used to build and test integrations against supported practice management systems, which is where much of NexHealth's differentiation as an infrastructure-style platform for dental and healthcare scheduling becomes most apparent.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
