INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Mobile & Desktop Apps$q$, $q$Apps for iOS, Android, Mac, and Windows so employees can call, message, and meet from any device.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Call Analytics & Reporting$q$, $q$Dashboards tracking call volume, duration, and team performance to help managers spot trends and staffing needs.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Voicemail-to-Email & Call Recording$q$, $q$Automatic voicemail transcription and call recording for compliance, training, and quality review.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Multi-Location Number Management$q$, $q$Centralized administration of phone numbers and routing across multiple offices or franchise locations.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Consolidates voice, video, chat, and contact center tools into one platform$q$, 0);
