INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Feature depth can feel like more than very small teams or solo users need$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Contact center and advanced analytics features may sit behind higher-tier plans$q$, 2);
